console.log('Fetching portfolio for:', address)
const response = await alchemy.portfolio.getTokensByWallet(
  portfolioAddresses,
  true,
  true,
  true
)
console.log('Portfolio response:', response)
console.log('Portfolio response structure:', JSON.stringify(response, null, 2))

const chainData = new Map<number, {
  chainId: number
  chainName: string
  valueUsd: number
  tokens: Array<{
    address: string
    symbol: string
    name: string
    balance: string
    balanceFormatted: string
    valueUsd: number
    priceUsd: number
    logo?: string
  }>
}>()
let totalValue = 0

// Try different response structures
const tokens = response?.data?.tokens || response?.tokens || []
console.log('Tokens found:', tokens.length)

if (tokens && tokens.length > 0) {
  for (const token of tokens) {
    console.log('Processing token:', token)

    const tokenData = token as any

    // Handle different possible structures
    const tokenAddress = tokenData.tokenAddress || tokenData.contractAddress || tokenData.address
    const network = tokenData.network || tokenData.chainId
    const tokenBalance = tokenData.tokenBalance || tokenData.balance || '0'
    const metadata = tokenData.tokenMetadata || tokenData.metadata || {}
    const prices = tokenData.tokenPrices || tokenData.prices || {}

    const decimals = metadata.decimals || 18
    const balance = parseFloat(tokenBalance) / Math.pow(10, decimals)

    console.log('Token details:', {
      symbol: metadata.symbol,
      balance,
      decimals,
      rawBalance: tokenBalance,
      network
    })

    // Skip tokens with zero balance
    if (balance === 0 || isNaN(balance)) {
      console.log('Skipping token with zero/invalid balance')
      continue
    }

    const chainId = supportedChains.find(c => c.network === network)?.id || 1

    if (!chainData.has(chainId)) {
      chainData.set(chainId, {
        chainId,
        chainName: supportedChains.find(c => c.id === chainId)?.name || 'Unknown',
        valueUsd: 0,
        tokens: []
      })
    }

    const chain = chainData.get(chainId)!
    const priceUsd = prices.usdPrice || prices.price || 0
    const valueUsd = balance * priceUsd

    console.log('Token value:', {
      symbol: metadata.symbol,
      balance,
      priceUsd,
      valueUsd
    })

    chain.tokens.push({
      address: tokenAddress,
      symbol: metadata.symbol || 'UNKNOWN',
      name: metadata.name || 'Unknown',
      balance: tokenBalance,
      balanceFormatted: balance.toFixed(6),
      valueUsd,
      priceUsd,
      logo: metadata.logo || metadata.logoURI,
    })

    chain.valueUsd += valueUsd
    totalValue += valueUsd
  }
}

console.log('Final portfolio data:', {
  totalValue,
  chains: Array.from(chainData.values())
})
